import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"锈壶","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/锈壶.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/锈壶.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/锈壶.md"};function l(i,a,_,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"锈壶",tabindex:"-1"},[s("锈壶 "),e("a",{class:"header-anchor",href:"#锈壶","aria-label":'Permalink to "锈壶"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="锈壶-1" tabindex="-1">锈壶 <a class="header-anchor" href="#锈壶-1" aria-label="Permalink to &quot;锈壶&quot;">​</a></h1><p>锈壶<br> “再去一次缺口”，军官如是说道。仿佛还有人相信这一切都是一部宏大戏剧，充满崇高抱负与伟大英雄。趁着军官走开在墙上刻下又一道标记，士兵又从壶中痛饮一大口。他看见自己死在战壕尽头，感觉自己已经半疯。威士忌缓和了恐惧，却无法阻止泪水顺着他的脸颊流下，在复面的污垢中冲出细小的河流。<br> 500<br> 特异本质<br> 描述：一件一战时期的随身扁酒壶，用粗糙的手工在“为了胜利”字样上刻下英国国旗和迷人裸女。尽管它是银质的，但却散发着旧铜的气味，还会在触碰它的手上留下锈斑。<br> 效果：壶中总是充满深琥珀色的威士忌，陈化极久却带有使人不快的金属味。喝光这壶中的酒使自己饮醉可以使凡人看见幽冥，这视为你获得了【灵视】，但也会因为醉酒获得一点不可豁免的【眩晕】，这是D级自然本质的【毒素】效果，免疫该效果将不可醉酒，当然也不会获得【灵视】。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
